     let (h, mi, s, _frac) = jdn_to_hms(jdn);
-    utc_offset_for_datetime(y as i32, mo as u32, d as u32, h as u32, mi as u32, s as u32)
+    utc_offset_for_local_datetime(y as i32, mo as u32, d as u32, h as u32, mi as u32, s as u32)
 }

